insight.code_example:
mutation {
  marketCreate(
    input: {
      name: "US Market"
      currencyCode: USD
      shippingZones: [
        {
          zone: {
            name: "Contiguous US"
            countries: [US]
            provinces: []
            postalCodeRanges: [
              { start: "10001", end: "99999" }
            ]
          }
          shippingRates: [
            {
              price: "10.00"
              weightRange: {
                greaterThanOrEqualTo: 0
                lessThan: 10
              }
            }
          ]
        }
      ]
    }
  ) {
    market {
      id
    }
    userErrors {
      field
      message
    }
  }
}
